            $script:emptyDir = Join-Path -Path ([System.IO.Path]::GetTempPath()) -ChildPath 'empty-test-dir'
            if (-not (Test-Path -Path $script:emptyDir)) {
                New-Item -Path $script:emptyDir -ItemType Directory | Out-Null
            }
        }
